import { Component, inject, ViewEncapsulation } from '@angular/core';
import { Router } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { NgClass } from '@angular/common'; // 🚀 Requis pour modifier dynamiquement les classes CSS
import { from } from 'rxjs';

@Component({
  selector: 'app-job-create',
  standalone: true,
  imports: [FormsModule, NgClass], // 🚀 Intégration étanche de NgClass
  templateUrl: './job-create.component.html',
  styleUrls: ['./job-create.component.css'],
  encapsulation: ViewEncapsulation.None 
})
export class JobCreateComponent {
  private router = inject(Router);

  // Objet de contrôle pour l'affichage de la notification flash
  notification = {
    show: false,
    message: '',
    type: 'success' as 'success' | 'error'
  };

  // Données synchronisées avec le HTML
  job = { 
    title: '', 
    contract_type: 'CDI', 
    location: '', 
    workplace_type: 'Présentiel', 
    salary: '', 
    experience_level: 'Junior (0-2 ans)', 
    missions_desc: '', 
    profile_desc: '', 
    expires_at: '' 
  };

  // Fonction utilitaire pour instancier la carte temporisée
  showFlashMessage(message: string, type: 'success' | 'error', callback?: () => void) {
    this.notification = { show: true, message, type };
    
    // Fermeture automatique après 3 secondes
    setTimeout(() => {
      this.notification.show = false;
      if (callback) callback();
    }, 3000);
  }

  onPublish(event: Event) {
    event.preventDefault(); // Coupe le rechargement de page

    // Validation locale obligatoire
    if (!this.job.title || !this.job.location || !this.job.missions_desc || !this.job.profile_desc) {
      this.showFlashMessage("Veuillez renseigner l'intégralité des champs obligatoires marqués d'un astérisque (*).", 'error');
      return;
    }

    console.log("Transmission directe au serveur :", this.job);

    // 🚀 ALIGNEMENT FORCE ET ETANCHE SUR L'IP LOCAL ET LE PORT 3000 DU BACKEND
    const targetUrl = 'http://localhost:3000/api/recruiter/jobs/create'; 
    const token = localStorage.getItem('token');

    // Génération de la promesse fetch native
    const promise = fetch(targetUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': token ? `Bearer ${token}` : '' // Transmet le Token JWT requis par verifyToken
      },
      body: JSON.stringify(this.job)
    }).then(async res => {
      if (!res.ok) {
        const errorBody = await res.json().catch(() => ({}));
        throw new Error(errorBody.message || "Erreur serveur.");
      }
      return res.json();
    });

    // Conversion en Observable pour conserver votre structure de souscription
    from(promise).subscribe({
      next: (res: any) => {
        const successMsg = res.message || "Annonce d'emploi diffusée avec succès sur TunJob Portal !";
        // Déclenche le Toast vert, puis redirige après disparition
        this.showFlashMessage(successMsg, 'success', () => {
          this.router.navigate(['/recruiter/job-manage']); 
        });
      },
      error: (err) => {
        console.error("Échec de l'insertion de l'annonce :", err);
        // Déclenche le Toast rouge sans casser le formulaire
        this.showFlashMessage("Impossible de diffuser l'offre. Vérifiez que votre serveur backend (Port 3000) et votre base de données MySQL sont actifs.", 'error');
      }
    });
  }
}
<!-- 🚀 NOTIFICATION FLASH PROFESSIONNELLE -->
@if (notification.show) {
  <div class="toast-notification" [ngClass]="notification.type">
    <div class="toast-content">
      <span class="toast-icon">{{ notification.type === 'success' ? '✅' : '❌' }}</span>
      <p class="toast-message">{{ notification.message }}</p>
    </div>
  </div>
}

<div class="form-container">
  <div class="form-card">
    <div class="card-header">
      <h3><i class="bi bi-file-earmark-medical-fill"></i> Rédaction d'une fiche de poste</h3>
      <p>Remplissez les critères requis pour diffuser votre annonce d'emploi en Tunisie.</p>
    </div>

    <!-- 🌟 CORRECTION : Injection de $event pour interdire au navigateur de figer ou recharger -->
    <form (ngSubmit)="onPublish($event)" class="job-form">
      
      <!-- Ligne 1 : Intitulé et Localisation -->
      <div class="form-row-2">
        <div class="form-group">
          <label for="title">Intitulé du poste *</label>
          <input type="text" id="title" name="title" [(ngModel)]="job.title" placeholder="Ex: Développeur Angular Senior" required>
        </div>
        
        <div class="form-group">
          <label for="location">Localisation *</label>
          <input type="text" id="location" name="location" [(ngModel)]="job.location" placeholder="Ex: Les Berges du Lac, Tunis" required>
        </div>
      </div>

      <!-- Ligne 2 : Type de contrat, Type de lieu et Date d'expiration -->
      <div class="form-row-3">
        <div class="form-group">
          <label for="contract_type">Type de contrat</label>
          <select id="contract_type" name="contract_type" [(ngModel)]="job.contract_type" class="form-select">
            <option value="CDI">CDI</option>
            <option value="CDD">CDD</option>
            <option value="SIVP">SIVP / Stage</option>
            <option value="Freelance">Freelance</option>
          </select>
        </div>

        <div class="form-group">
          <label for="workplace_type">Mode de travail</label>
          <select id="workplace_type" name="workplace_type" [(ngModel)]="job.workplace_type" class="form-select">
            <option value="Présentiel">Présentiel</option>
            <option value="Hybride">Hybride</option>
            <option value="Télétravail">Télétravail à 100%</option>
          </select>
        </div>

        <div class="form-group">
          <label for="expires_at">Expire le</label>
          <input type="date" id="expires_at" name="expires_at" [(ngModel)]="job.expires_at">
        </div>
      </div>

      <!-- Ligne 3 : Salaire et Niveau d'expérience -->
      <div class="form-row-2">
        <div class="form-group">
          <label for="salary">Salaire indicatif (Optionnel)</label>
          <input type="text" id="salary" name="salary" [(ngModel)]="job.salary" placeholder="Ex: 1500 - 2200 DT">
        </div>

        <div class="form-group">
          <label for="experience_level">Niveau d'expérience requis</label>
          <select id="experience_level" name="experience_level" [(ngModel)]="job.experience_level" class="form-select">
            <option value="Junior (0-2 ans)">Junior (0-2 ans)</option>
            <option value="Intermédiaire (2-5 ans)">Intermédiaire (2-5 ans)</option>
            <option value="Senior (5+ ans)">Senior (5+ ans)</option>
          </select>
        </div>
      </div>

      <!-- Textareas : Missions et Profil recherché -->
      <div class="form-group">
        <label for="missions">Missions principales *</label>
        <textarea id="missions" name="missions_desc" [(ngModel)]="job.missions_desc" rows="5" placeholder="Décrivez les responsabilités quotidiennes et les projets techniques..." required></textarea>
      </div>

      <div class="form-group">
        <label for="profile">Profil recherché & Prérequis *</label>
        <textarea id="profile" name="profile_desc" [(ngModel)]="job.profile_desc" rows="5" placeholder="Compétences clés, technologies maîtrisées, soft skills..." required></textarea>
      </div>

      <!-- Actions boutons -->
      <div class="form-actions">
        <!-- 🌟 CORRECTION : type="submit" forcé pour déclencher l'action de soumission synchrone -->
        <button type="submit" class="btn-submit-job">
          <i class="bi bi-rocket-takeoff-fill"></i> Diffuser l'annonce
        </button>
      </div>

    </form>
  </div>
</div>
